// Path to current temp test repo (empty if none active)
static wchar_t g_write_test_repo[512] = {};

// delete_directory_recursive is now in file_io.cpp (used by clone cleanup)

// Recursively copy directory
// Exported for use by other test files (test_reset.cpp, test_cherry_pick.cpp)
bool copy_directory_recursive(const wchar_t* src, const wchar_t* dst) {
    if (!src || !dst) return false;

    // Create destination directory
    if (!CreateDirectoryW(dst, nullptr)) {
        DWORD err = GetLastError();
        if (err != ERROR_ALREADY_EXISTS) {
            return false;
        }
    }

    wchar_t search_path[512];
    wcscpy_s(search_path, src);
    wcscat_s(search_path, L"\\*");

    WIN32_FIND_DATAW find_data;
    HANDLE find_handle = FindFirstFileW(search_path, &find_data);
    if (find_handle == INVALID_HANDLE_VALUE) {
        return false;
    }

    bool success = true;
    do {
        // Skip . and ..
        if (wcscmp(find_data.cFileName, L".") == 0 ||
            wcscmp(find_data.cFileName, L"..") == 0) {
            continue;
        }

        wchar_t src_path[512], dst_path[512];
        wcscpy_s(src_path, src);
        wcscat_s(src_path, L"\\");
        wcscat_s(src_path, find_data.cFileName);

        wcscpy_s(dst_path, dst);
        wcscat_s(dst_path, L"\\");
        wcscat_s(dst_path, find_data.cFileName);

        if (find_data.dwFileAttributes & FILE_ATTRIBUTE_DIRECTORY) {
            // Recurse into subdirectory
            if (!copy_directory_recursive(src_path, dst_path)) {
                success = false;
            }
        } else {
            // Copy file
            if (!CopyFileW(src_path, dst_path, FALSE)) {
                success = false;
            }
        }
    } while (FindNextFileW(find_handle, &find_data));

    FindClose(find_handle);
    return success;
}

// Create fresh temp copy of fixture repo
// Returns: true if successful, sets g_write_test_repo
static bool create_write_test_repo() {
    // First, cleanup any stale temp repo from previous run
    if (g_write_test_repo[0] != L'\0') {
        delete_directory_recursive(g_write_test_repo);
        g_write_test_repo[0] = L'\0';
    }

    // Get TEMP directory
    wchar_t temp_base[512];
    DWORD len = GetTempPathW(512, temp_base);
    if (len == 0 || len >= 512) {
        return false;
    }

    // Create unique temp directory
    wchar_t temp_path[512];
    wcscpy_s(temp_path, temp_base);
    wcscat_s(temp_path, L"GitSmarter_write_test_");

    // Append timestamp for uniqueness
    LARGE_INTEGER counter;
    QueryPerformanceCounter(&counter);
    wchar_t suffix[32];
    swprintf_s(suffix, L"%llx", counter.QuadPart);
    wcscat_s(temp_path, suffix);

    // Copy fixture repo to temp location
    if (!copy_directory_recursive(WRITE_TEST_FIXTURE_PATH, temp_path)) {
        delete_directory_recursive(temp_path);
        return false;
    }

    wcscpy_s(g_write_test_repo, temp_path);
    return true;
}

// Delete temp repo and clear g_write_test_repo
static void cleanup_write_test_repo() {
    if (g_write_test_repo[0] != L'\0') {
        delete_directory_recursive(g_write_test_repo);
        g_write_test_repo[0] = L'\0';
    }
}

// Check if loose object file exists in repo
static bool object_file_exists(GitRepository* repo, const char* sha) {
    if (!repo || !sha || strlen(sha) < 40) return false;

    wchar_t git_dir_wide[Git::MAX_PATH_LEN];
    MultiByteToWideChar(CP_UTF8, 0, repo->git_dir, -1, git_dir_wide, Git::MAX_PATH_LEN);

    wchar_t obj_path[Git::MAX_PATH_LEN];
    wcscpy_s(obj_path, git_dir_wide);
    wcscat_s(obj_path, L"\\objects\\");

    // First 2 chars are directory
    wchar_t subdir[3] = { static_cast<wchar_t>(sha[0]), static_cast<wchar_t>(sha[1]), 0 };
    wcscat_s(obj_path, subdir);
    wcscat_s(obj_path, L"\\");

    // Remaining 38 chars are filename
    wchar_t filename[39];
    for (int i = 0; i < 38; i++) {
        filename[i] = static_cast<wchar_t>(sha[i + 2]);
    }
    filename[38] = 0;
    wcscat_s(obj_path, filename);

    return file_exists(obj_path);
}

