TEST(write_object_tree_basic) {
    if (!create_write_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_write_test_repo)) {
        cleanup_write_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    // First write a blob
    const char* blob_content = "test content";
    char blob_sha[41] = {};
    TEST_ASSERT_TRUE(git_write_object(&repo, GitObjectType::Blob,
                                       blob_content, strlen(blob_content), blob_sha));

    // Build tree content manually: mode SP name NUL sha(20bytes)
    uint8_t tree_content[128];
    uint8_t* ptr = tree_content;

    // "100644 test.txt\0<sha>"
    const char* mode_name = "100644 test.txt";
    memcpy(ptr, mode_name, strlen(mode_name) + 1);  // Include null
    ptr += strlen(mode_name) + 1;

    // Convert hex SHA to raw bytes
    uint8_t blob_sha_raw[20];
    hex_to_sha(blob_sha, blob_sha_raw);
    memcpy(ptr, blob_sha_raw, 20);
    ptr += 20;

    size_t tree_size = ptr - tree_content;
    char tree_sha[41] = {};
    bool result = git_write_object(&repo, GitObjectType::Tree,
                                    tree_content, tree_size, tree_sha);

    TEST_ASSERT_TRUE(result);
    TEST_ASSERT_EQ(strlen(tree_sha), 40);

    git_repo_close(&repo);
    cleanup_write_test_repo();
}

