TEST(write_tree_from_index_nested) {
    if (!create_write_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_write_test_repo)) {
        cleanup_write_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    char tree_sha[41] = {};
    TEST_ASSERT_TRUE(git_write_tree_from_index(&repo, tree_sha));

    // Read tree and verify subdir entry
    GitTreeEntry entries[64];
    size_t count = git_read_tree(&repo, tree_sha, entries, 64);
    TEST_ASSERT_TRUE(count > 0);

    bool found_subdir = false;
    for (size_t i = 0; i < count; i++) {
        if (strcmp(entries[i].name, "subdir") == 0) {
            TEST_ASSERT_EQ(entries[i].mode, Git::MODE_TREE);
            found_subdir = true;
            break;
        }
    }
    TEST_ASSERT_TRUE(found_subdir);

    git_repo_close(&repo);
    cleanup_write_test_repo();
}

