TEST(commit_create_multi_parents) {
    if (!create_write_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_write_test_repo)) {
        cleanup_write_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    // Get two commits for parents: HEAD and its parent
    GitCommit head = {};
    TEST_ASSERT_TRUE(git_read_commit(&repo, repo.head_sha, &head));

    if (strlen(head.parent_sha) == 0) {
        git_repo_close(&repo);
        cleanup_write_test_repo();
        TEST_SKIP("HEAD has no parent for merge test");
    }

    // Create merge commit using the multi-parent API
    // We need to use git_commit_create_multi which isn't exposed in app.h
    // Instead, test using direct object write with two parent lines

    char commit_content[2048];
    snprintf(commit_content, sizeof(commit_content),
             "tree %s\n"
             "parent %s\n"
             "parent %s\n"
             "author Merge Test <merge@test.com> 1234567890 +0000\n"
             "committer Merge Test <merge@test.com> 1234567890 +0000\n"
             "\n"
             "Merge commit\n",
             head.tree_sha, repo.head_sha, head.parent_sha);

    char merge_sha[41] = {};
    TEST_ASSERT_TRUE(git_write_object(&repo, GitObjectType::Commit,
                                       commit_content, strlen(commit_content), merge_sha));

    // Read it back and verify both parents
    GitCommit merge_commit = {};
    TEST_ASSERT_TRUE(git_read_commit(&repo, merge_sha, &merge_commit));
    TEST_ASSERT_STREQ(merge_commit.parent_sha, repo.head_sha);
    TEST_ASSERT_STREQ(merge_commit.parent2_sha, head.parent_sha);

    git_repo_close(&repo);
    cleanup_write_test_repo();
}

