TEST(tag_create_lightweight) {
    if (!create_write_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_write_test_repo)) {
        cleanup_write_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    char error[256] = {};
    bool result = git_tag_create(&repo, "v1.0.0", repo.head_sha, nullptr, error, sizeof(error));
    TEST_ASSERT_TRUE(result);
    TEST_ASSERT_TRUE(git_tag_exists(&repo, "v1.0.0"));

    // Verify the tag points to the correct commit
    GitRef refs[100];
    size_t count = git_list_refs(&repo, refs, 100);
    bool found = false;
    for (size_t i = 0; i < count; i++) {
        if (refs[i].type == GitRef::Type::Tag && strcmp(refs[i].name, "v1.0.0") == 0) {
            TEST_ASSERT_STREQ(refs[i].sha, repo.head_sha);
            found = true;
            break;
        }
    }
    TEST_ASSERT_TRUE(found);

    git_repo_close(&repo);
    cleanup_write_test_repo();
}

